+}
+
+impl DecisionEvidence {
+    /// Create a simple decision with rule and action.
+    pub fn simple(rule: impl Into<String>, action: impl Into<String>) -> Self {
+        Self {
+            rule: rule.into(),
+            inputs_summary: String::new(),
+            action: action.into(),
+            confidence: None,
+            alternatives: vec![],
+            explanation: String::new(),
+        }
